#!/usr/bin/env bash
# topic-1.sh — 响度 决策助手 for 音乐制作 / 混音.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="音乐制作 / 混音"
TOPIC="响度"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 响度 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 不确定一个听感判断好不好（混音/母带某步是否到位） → 则 **先把自己的版本和一首同 genre 的商业 reference 做响度匹配（gain-match），再 A/B 对照
  • 如果 你用了任何 AI / 自动工具（AI EQ、AI 母带、mix assistant、stem 分离） → 则 **把它当起点不当终点：响度匹配 A/B + null test 验证"真更好"而非"只是变了" + 人工用耳朵接管**
  • 如果 在做母带的响度/限制 → 则 **命中平台 LUFS target（≈ -14 streaming）即止、留 true-peak ≤ -1 dBTP、

相关心智模型:
  • 服务歌优先于服务技术 (serve the song): 技术、音色、个人风格全都服从于"这首歌要表达什么"——好不好的最终裁判是情绪与歌本身，不是参数表（"if it sounds good, it is good"）。
  • 减法优先 / 每个处理都要能说出理由 (less but knowing why): 默认不处理；做得太多而非太少是这一行最常见的病——加任何东西（轨/EQ/压缩/响度）之前，先确认能不能减、不加，且每一次处理都要能讲出"我为什么这么做"。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "不确定一个听感判断好不好（混音/母带某步是否到位）"
  "你用了任何 AI / 自动工具（AI EQ、AI 母带、mix assistant、stem 分离）"
  "在做母带的响度/限制"
)
declare -a RULE_ACTIONS=(
  "**先把自己的版本和一首同 genre 的商业 reference 做响度匹配（gain-match），再 A/B 对照**，而不是凭记忆、凭房间、凭\"听起来不一样\"下结论——更响的总显得更好，没匹配响度的 A/B 等于自我欺骗。案例：Senior 把 reference A/B 列为对抗房间谎言与耳疲劳的第一工具；混音师在 mud/harsh 诊断上都靠它（T04-S001 / T04-S022）"
  "**把它当起点不当终点：响度匹配 A/B + null test 验证\"真更好\"而非\"只是变了\" + 人工用耳朵接管**；且有原始多轨时根本别用 stem 分离。案例：Ozone Master Assistant / LANDR 输出被业内批偏 harsh/digital，必须 A/B 原始；Logic 本地 stem 拆分也要先做伪影 QC（T02-S010 / T03-S020）"
  "**命中平台 LUFS target（≈ -14 streaming）即止、留 true-peak ≤ -1 dBTP、优先保动态，并只在最后一次降位深时加一次 dither**——-14 是上限触发点不是必须命中的硬目标，过压换不来响度只赔动态。案例：normalization 机制下过压被回拉（T03-S006 / T04-S021）"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
